@startuml
skinparam packageStyle folder
skinparam rectangle {
  BackgroundColor<<AGGREGATE>> LightGray
  BorderColor<<AGGREGATE>> DarkGray
  FontColor<<AGGREGATE>> DarkGray
}
skinparam rectangle {
  BackgroundColor<<AGGREGATE ROOT>> LightGray
  BorderColor<<AGGREGATE ROOT>> DarkGray
  FontColor<<AGGREGATE ROOT>> DarkGray
}
skinparam rectangle {
  BackgroundColor<<ENTITY>> LightGray
  BorderColor<<ENTITY>> DarkGray
  FontColor<<ENTITY>> DarkGray
}

package "Task" <<AGGREGATE>> {
  rectangle "Task" <<AGGREGATE ROOT>> <<ENTITY>> as Task
}

package "UserStory" <<AGGREGATE>> {
  rectangle "UserStory" <<AGGREGATE ROOT>> <<ENTITY>> as UserStory
}

package "Sprint" <<AGGREGATE>> {
  rectangle "Sprint" <<AGGREGATE ROOT>> <<ENTITY>> as Sprint
}

package "Typology" <<AGGREGATE>> {
  rectangle "Typology" <<AGGREGATE ROOT>> <<ENTITY>> as Typology
}

package "Project" <<AGGREGATE>> {
  rectangle "Project" <<AGGREGATE ROOT>> <<ENTITY>> as Project
  rectangle "Resource" <<AGGREGATE ROOT>> <<ENTITY>> as ProjectResource
}

package "ProfileRequest" <<AGGREGATE>> {
  rectangle "ProfileRequest" <<AGGREGATE ROOT>> <<ENTITY>> as ProfileRequest
}

package "Profile" <<AGGREGATE>> {
  rectangle "Profile" <<AGGREGATE ROOT>> <<ENTITY>> as Profile
}

package "Resource" <<AGGREGATE>> {
  rectangle "Resource" <<AGGREGATE ROOT>> <<ENTITY>> as Resource
}

package "User" <<AGGREGATE>> {
  rectangle "User" <<AGGREGATE ROOT>> <<ENTITY>> as User
}

Task --> Sprint
Task --> ProjectResource
Sprint --> UserStory
Sprint --> ProjectResource
UserStory --> ProjectResource
Typology --> Profile
ProfileRequest --> User
Profile --> User
Profile --> ProjectResource
Resource --> User
@enduml
